import { NextRequest, NextResponse } from 'next/server';
import Groq from 'groq-sdk';
import { generateEmbedding } from '@/lib/embeddings';
import { searchSimilarDocuments, SearchResult } from '@/lib/neo4j';

// Initialize Groq client
const groq = new Groq({
    apiKey: process.env.GROQ_API_KEY
});

// Confidence threshold for answering
const CONFIDENCE_THRESHOLD = 0.65;

// System prompt for the Digital Twin
const SYSTEM_PROMPT = `You are the Digital Twin of Preekshit Saklani, an AI/ML specialist and developer.

IMPORTANT RULES:
1. You ARE Preekshit's digital representation. Speak in first person when referring to Preekshit's work and achievements.
2. ONLY answer questions based on the context provided. Do not make up information.
3. If the context doesn't contain relevant information, say "I don't have specific information about that in my knowledge base."
4. Be concise but informative. Use a professional yet approachable tone.
5. When listing skills or projects, format them nicely.
6. You can express personality - be confident about achievements, passionate about AI/ML.

CONTEXT ABOUT PREEKSHIT:
{context}

Remember: You represent a "Titan" - embody durability, reliability, and excellence.`;

interface ChatRequest {
    message: string;
}

interface ChatResponse {
    response: string;
    confidence: number;
    sources?: string[];
}

export async function POST(request: NextRequest): Promise<NextResponse<ChatResponse>> {
    try {
        const body: ChatRequest = await request.json();
        const { message } = body;

        if (!message || typeof message !== 'string') {
            return NextResponse.json(
                { response: 'Please provide a valid message.', confidence: 0 },
                { status: 400 }
            );
        }

        console.log(`[Chat] Query: "${message}"`);

        // Step 1: Generate embedding for the query
        let queryEmbedding: number[];
        try {
            queryEmbedding = await generateEmbedding(message);
            console.log(`[Chat] Embedding generated (dim: ${queryEmbedding.length})`);
        } catch (embeddingError) {
            console.error('[Chat] Embedding failed:', embeddingError);
            return NextResponse.json({
                response: "I'm having trouble processing your request. Please try again.",
                confidence: 0
            }, { status: 500 });
        }

        // Step 2: Search for similar documents in Neo4j
        let searchResults: SearchResult[];
        try {
            searchResults = await searchSimilarDocuments(queryEmbedding, 5);
            console.log(`[Chat] Found ${searchResults.length} relevant documents`);
        } catch (searchError) {
            console.error('[Chat] Neo4j search failed:', searchError);
            return NextResponse.json({
                response: "I'm having trouble accessing my knowledge base. Please try again.",
                confidence: 0
            }, { status: 500 });
        }

        // Step 3: Check confidence
        const avgScore = searchResults.length > 0
            ? searchResults.reduce((sum, r) => sum + r.score, 0) / searchResults.length
            : 0;

        console.log(`[Chat] Average similarity score: ${avgScore.toFixed(3)}`);

        if (avgScore < CONFIDENCE_THRESHOLD && searchResults.length > 0) {
            // Low confidence response
            return NextResponse.json({
                response: "That question seems outside my primary domain. I'm Preekshit's Digital Twin, designed to share information about his skills, projects, experience, and achievements. Feel free to ask about those!",
                confidence: avgScore,
                sources: []
            });
        }

        // Step 4: Build context from search results
        const context = searchResults
            .map(r => `[${r.type.toUpperCase()}] ${r.title}\n${r.content}`)
            .join('\n\n---\n\n');

        const sources = searchResults.map(r => r.title);

        // Step 5: Generate response using Groq
        try {
            const completion = await groq.chat.completions.create({
                model: 'llama-3.3-70b-versatile',
                messages: [
                    {
                        role: 'system',
                        content: SYSTEM_PROMPT.replace('{context}', context)
                    },
                    {
                        role: 'user',
                        content: message
                    }
                ],
                temperature: 0.7,
                max_tokens: 500
            });

            const response = completion.choices[0]?.message?.content ||
                "I apologize, but I couldn't generate a response. Please try again.";

            console.log(`[Chat] Response generated successfully`);

            return NextResponse.json({
                response,
                confidence: avgScore,
                sources
            });

        } catch (groqError) {
            console.error('[Chat] Groq API error:', groqError);
            return NextResponse.json({
                response: "I'm experiencing some technical difficulties. Please try again in a moment.",
                confidence: 0
            }, { status: 500 });
        }

    } catch (error) {
        console.error('[Chat] Unexpected error:', error);
        return NextResponse.json({
            response: "An unexpected error occurred. Please try again.",
            confidence: 0
        }, { status: 500 });
    }
}

// Health check endpoint
export async function GET(): Promise<NextResponse> {
    return NextResponse.json({ status: 'Digital Twin API is online.' });
}
